// Test successful person creation via service
var mockRepository = new Mock<IPersonRepository>();
mockRepository
    .Setup(r => r.GetByEmailAsync("john.doe@example.com"))
    .ReturnsAsync((Person)null);  // No duplicate
mockRepository
    .Setup(r => r.GetByIdentityNumberAsync("123456789"))
    .ReturnsAsync((Person)null);  // No duplicate
mockRepository
    .Setup(r => r.AddAsync(It.IsAny<Person>()))
    .ReturnsAsync(true);

var service = new PersonService(mockRepository.Object);
var result = await service.CreatePersonAsync(
    firstName: "John",
    lastName: "Doe",
    email: "john.doe@example.com",
    identityNumber: "123456789",
    birthDate: new DateTime(1990, 1, 1),
    phone: "555-1234"
);

Assert.That(result, Is.True);
mockRepository.Verify(r => r.AddAsync(It.IsAny<Person>()), Times.Once);

