// Test repository AddAsync successfully saves person to database
var options = new DbContextOptionsBuilder<UCRDatabaseContext>()
    .UseInMemoryDatabase(databaseName: "TestDb_AddPerson")
    .Options;

using var context = new UCRDatabaseContext(options);
var repository = new PersonRepository(context);

var person = new Person(
    Guid.NewGuid(),
    "John",
    "Doe",
    "john.doe@example.com",
    "123456789",
    new DateTime(1990, 1, 1),
    "555-1234"
);

var result = await repository.AddAsync(person);

Assert.That(result, Is.True);
Assert.That(context.Persons.Count(), Is.EqualTo(1));
var savedPerson = await context.Persons.FirstOrDefaultAsync();
Assert.That(savedPerson.Email, Is.EqualTo("john.doe@example.com"));

// Test GetByEmailAsync returns person when email exists
var options = new DbContextOptionsBuilder<UCRDatabaseContext>()
    .UseInMemoryDatabase(databaseName: "TestDb_GetByEmail")
    .Options;

using var context = new UCRDatabaseContext(options);
var person = new Person(
    Guid.NewGuid(),
    "John",
    "Doe",
    "john.doe@example.com",
    "123456789",
    new DateTime(1990, 1, 1),
    "555-1234"
);
context.Persons.Add(person);
await context.SaveChangesAsync();

var repository = new PersonRepository(context);
var result = await repository.GetByEmailAsync("john.doe@example.com");

Assert.That(result, Is.Not.Null);
Assert.That(result.Email, Is.EqualTo("john.doe@example.com"));

